// === USER PROFILE / CV ===
// Edit USER_CV below with your real CV text. The AI agent uses it to
// match skills, score relevance, and identify gaps. Keep it concise (<2000 chars).
const USER_CV = `
Name: Your Name
Target Roles: Project Manager, Product Manager, Scrum Master, AI Project Manager, Program Manager
Experience: 0-3 years (entry to mid level)
Skills: Agile, Scrum, Jira, Confluence, Trello, Asana, Notion, stakeholder communication, sprint planning, roadmaps, requirements gathering, basic SQL, Google Workspace, MS Office, AI tools (ChatGPT, n8n, Zapier).
Domains: SaaS, AI, automation, fintech (open).
Certifications (optional): CSM in progress, Google PM Certificate.
Location: Remote / Worldwide.
`.trim();

return [{ json: { user_cv: USER_CV } }];

// === NORMALIZE ALL SOURCES INTO A UNIFIED SCHEMA ===
// Each upstream HTTP node returns a single item whose .json may contain:
//   - Remotive:  { jobs: [...] }
//   - Arbeitnow: { data: [...] }
//   - RemoteOK:  [legal, ...jobs]  (array, first item is legal notice)

const out = [];

for (const item of items) {
  const payload = item.json;

  // Remotive
  if (payload && Array.isArray(payload.jobs)) {
    for (const j of payload.jobs) {
      out.push({
        id: `remotive-${j.id}`,
        source: 'Remotive',
        title: j.title || '',
        company: j.company_name || '',
        location: j.candidate_required_location || 'Remote',
        url: j.url || '',
        description: (j.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1200),
        tags: j.tags || [],
        publication_date: j.publication_date || null,
        job_type: j.job_type || ''
      });
    }
    continue;
  }

  // Arbeitnow
  if (payload && Array.isArray(payload.data)) {
    for (const j of payload.data) {
      out.push({
        id: `arbeitnow-${j.slug || j.url}`,
        source: 'Arbeitnow',
        title: j.title || '',
        company: j.company_name || '',
        location: (j.location || (j.remote ? 'Remote' : '')) || '',
        url: j.url || '',
        description: (j.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1200),
        tags: j.tags || [],
        publication_date: j.created_at ? new Date(j.created_at * 1000).toISOString() : null,
        job_type: (j.job_types || []).join(',')
      });
    }
    continue;
  }

  // RemoteOK (root array)
  if (Array.isArray(payload)) {
    for (const j of payload) {
      if (!j || !j.position) continue; // skip legal notice
      out.push({
        id: `remoteok-${j.id}`,
        source: 'RemoteOK',
        title: j.position || '',
        company: j.company || '',
        location: j.location || 'Remote',
        url: j.url || j.apply_url || '',
        description: (j.description || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1200),
        tags: j.tags || [],
        publication_date: j.date || null,
        job_type: ''
      });
    }
    continue;
  }
}

return out.map(j => ({ json: j }));

// === PRE-FILTER: keep only remote PM/Product/Scrum-ish roles ===
const titleRe = /(project\s*manager|product\s*manager|program\s*manager|scrum\s*master|associate\s*pm|junior\s*pm|apm|product\s*owner)/i;
const seniorRe = /(senior|sr\.|staff|principal|lead|director|head\s+of|vp|chief|manager\s+of\s+managers)/i;
const remoteRe = /(remote|worldwide|anywhere|distributed)/i;

const kept = [];
for (const item of items) {
  const j = item.json;
  const title = (j.title || '').toString();
  const loc = (j.location || '').toString();
  if (!titleRe.test(title)) continue;
  if (seniorRe.test(title)) continue;
  if (!remoteRe.test(loc) && !remoteRe.test(title)) continue;
  kept.push({ json: j });
}
return kept;

// === DEDUPE against existing DB rows ===
// Input branch 1 = normalized new jobs (each item.json has .id, .url, .title, .company)
// Input branch 2 = existing rows from Sheets/Notion (each item.json has at least Link or ID column)
//
// We split items by presence of a typical normalized field.
const existing = new Set();
const incoming = [];

for (const item of items) {
  const j = item.json || {};
  // Heuristic: existing rows usually have 'Link' or 'ID' columns; new ones have 'url' + 'source'
  if (j.source && j.url) {
    incoming.push(j);
  } else {
    const key = (j.ID || j.Link || j.url || '').toString();
    if (key) existing.add(key);
  }
}

const fresh = incoming.filter(j => !existing.has(j.id) && !existing.has(j.url));
return fresh.map(j => ({ json: j }));

// === BATCH all fresh jobs + attach USER_CV into ONE item for the AI agent ===
let userCv = '';
try { userCv = $items('User CV (edit me)')[0].json.user_cv || ''; } catch (e) { userCv = ''; }

const payload = items.map(i => ({
  id: i.json.id,
  source: i.json.source,
  title: i.json.title,
  company: i.json.company,
  location: i.json.location,
  url: i.json.url,
  description: (i.json.description || '').slice(0, 800)
}));

return [{ json: { user_cv: userCv, jobs: payload, count: payload.length } }];

