// === PARSE AI OUTPUT into individual rows for the DB ===
const raw = items[0]?.json;
let arr = [];

const content = raw?.message?.content ?? raw?.choices?.[0]?.message?.content ?? raw?.content ?? raw;
try {
  arr = typeof content === 'string' ? JSON.parse(content) : (Array.isArray(content) ? content : (content?.jobs || []));
} catch (e) {
  const m = String(content).match(/\[[\s\S]*\]/);
  if (m) { try { arr = JSON.parse(m[0]); } catch (_) { arr = []; } }
}

const today = new Date().toISOString().slice(0, 10);
return (arr || []).slice(0, 10).map(j => ({
  json: {
    Date: today,
    Title: j.title || '',
    Company: j.company || '',
    Location: j.location || '',
    Score: j.score ?? '',
    Link: j.apply_link || j.link || j.url || '',
    Status: 'New',
    Source: j.source || 'API',
    Summary: j.summary || '',
    Reason: j.reason || '',
    SkillsMatch: Array.isArray(j.skills_match) ? j.skills_match.join(', ') : (j.skills_match || ''),
    SkillsMissing: Array.isArray(j.skills_missing) ? j.skills_missing.join(', ') : (j.skills_missing || '')
  }
}));

// === BUILD a single email digest item from all rows ===
const rows = items.map(i => i.json);
const top3 = rows.slice(0, 3);

const text = [
  'Top Remote Jobs for You 🚀',
  '',
  'Here are your best opportunities today:',
  '',
  ...top3.map((r, i) => `${i + 1}. ${r.Title} — ${r.Company}\n   ${r.Link}`),
  '',
  'Full ranked list:',
  ...rows.map((r, i) => `${i + 1}. [${r.Score}/10] ${r.Title} — ${r.Company} (${r.Source})\n   📍 ${r.Location}\n   🧾 ${r.Summary}\n   💡 ${r.Reason}\n   ✅ Match: ${r.SkillsMatch}\n   ⚠️  Gaps: ${r.SkillsMissing}\n   🔗 ${r.Link}`),
  '',
  'Action: apply to the top 3 today and update Status in the dashboard.'
].join('\n');

const html = `
<h2>🚀 Top Remote Jobs for You</h2>
<p>Here are your best opportunities today.</p>
<h3>⚡ Apply first</h3>
<ol>
${top3.map(r => `<li><b>${r.Title}</b> — ${r.Company}<br><a href="${r.Link}">Apply →</a></li>`).join('')}
</ol>
<h3>📊 Full ranked list</h3>
<ol>
${rows.map(r => `<li><b>${r.Title}</b> — ${r.Company}<br>📍 ${r.Location} &nbsp; ⭐ ${r.Score}/10 &nbsp; <i>${r.Source}</i><br><b>Summary:</b> ${r.Summary}<br><b>Why it fits:</b> ${r.Reason}<br><b>✅ Match:</b> ${r.SkillsMatch}<br><b>⚠️ Gaps:</b> ${r.SkillsMissing}<br><a href="${r.Link}">Apply →</a></li>`).join('')}
</ol>
<p><i>Stay consistent — apply to the top 3 today.</i></p>
`;

return [{ json: { count: rows.length, text, html } }];
